<script setup lang="ts">import{onMounted,ref}from'vue';import{BadgeDollarSign,RefreshCw,ShieldAlert,UsersRound,WalletCards}from'@lucide/vue';import{getOperatorDashboard}from'@/api/operator';import type{OperatorDashboard}from'@/types';import{useI18n}from'vue-i18n';const{t}=useI18n();const data=ref<OperatorDashboard|null>(null),loading=ref(false),error=ref('');const money=(v=0)=>new Intl.NumberFormat(undefined,{style:'currency',currency:'USD',maximumFractionDigits:6}).format(v/1_000_000);async function load(){loading.value=true;try{data.value=await getOperatorDashboard()}catch(e){error.value=e instanceof Error?e.message:t('common.failed')}finally{loading.value=false}}onMounted(load);</script>
<template><main class="content"><section class="page-header"><div><h1>{{t('operator.title')}}</h1><p>{{t('operator.subtitle')}}</p></div><button class="button secondary" :disabled="loading" @click="load"><RefreshCw :size="17"/>{{t('common.refresh')}}</button></section><div v-if="error" class="notice">{{error}}</div><section class="metric-grid"><article class="metric-card"><span class="metric-icon"><UsersRound :size="18"/></span><div><span>{{t('operatorDomain.customers')}}</span><strong>{{data?.customers||0}}</strong><small>{{data?.active_customers||0}} {{t('dashboard.active')}}</small></div></article><article class="metric-card"><span class="metric-icon"><BadgeDollarSign :size="18"/></span><div><span>{{t('operatorDomain.plans')}}</span><strong>{{data?.plans||0}}</strong><small>{{t('operatorDomain.pricing')}}</small></div></article><article class="metric-card"><span class="metric-icon"><WalletCards :size="18"/></span><div><span>{{t('operatorDomain.balance')}}</span><strong>{{money(data?.balance_micros)}}</strong><small>{{t('operatorDomain.balances')}}</small></div></article><article class="metric-card"><span class="metric-icon"><ShieldAlert :size="18"/></span><div><span>{{t('operatorDomain.risk')}}</span><strong>{{data?.risk_rules||0}}</strong><small>{{data?.published_notices||0}} {{t('operatorDomain.notices')}}</small></div></article></section><section class="grid section-gap"><section class="panel"><div class="panel-header"><h2>{{t('operatorDomain.customerOperations')}}</h2></div><div class="panel-body row-actions"><RouterLink class="button secondary" to="/operator/customers">{{t('operatorDomain.customers')}}</RouterLink><RouterLink class="button secondary" to="/operator/customer-groups">{{t('operatorDomain.groups')}}</RouterLink><RouterLink class="button secondary" to="/operator/plans">{{t('operatorDomain.plans')}}</RouterLink><RouterLink class="button secondary" to="/operator/balances">{{t('operatorDomain.balances')}}</RouterLink></div></section><section class="panel"><div class="panel-header"><h2>{{t('operatorDomain.operations')}}</h2></div><div class="panel-body row-actions"><RouterLink class="button secondary" to="/operator/pricing">{{t('operatorDomain.pricing')}}</RouterLink><RouterLink class="button secondary" to="/operator/risk">{{t('operatorDomain.risk')}}</RouterLink><RouterLink class="button secondary" to="/operator/notices">{{t('operatorDomain.notices')}}</RouterLink><RouterLink class="button secondary" to="/operator/usage">{{t('operator.traffic')}}</RouterLink></div></section></section></main></template>
